using UnityEngine;

// Condições de desactivação de inimigos baseadas em variáveis globais
// (Enemy Creator — Etapa 5.4). Avaliadas a cada frame por
// EnemyController.Update (deactivationConditions): quando uma devolve true, o
// inimigo passa a Desactivado (estado terminal) e assim permanece — mesmo
// após reentrar na área, a condição continua verdadeira e volta a desactivá-lo
// (a persistência do respawn é tratada na Etapa 7.3).
//
// Exemplo (GDD): uma alavanca (Etapa 6.1) põe a variável global
// "TorretaSala01Desativada" a true/1 — todas as torretas com esta condição
// desligam ao mesmo tempo (Drone/Torreta/porta/laser/máquina aquática/sensor/
// hazard móvel).

/// <summary>Desactiva o inimigo quando uma variável global BOOL (GameVariables) tem o valor esperado.</summary>
[System.Serializable]
public class Condition_GlobalBoolVariable : EnemyCondition
{
    [Tooltip("Nome da variável global (GameVariables). Se não existir, é tratada como false.")]
    public string variableName;

    [Tooltip("Valor que desactiva o inimigo (ex: \"TorretaSala01Desativada\" = true).")]
    public bool expectedValue = true;

    public override bool Evaluate(EnemyController enemy)
    {
        var vars = GameVariables.Instance;
        return vars != null && vars.GetBool(variableName) == expectedValue;
    }
}

/// <summary>Desactiva o inimigo quando uma variável global INT (GameVariables) cumpre a comparação.</summary>
[System.Serializable]
public class Condition_GlobalIntVariable : EnemyCondition
{
    [Tooltip("Nome da variável global (GameVariables). Se não existir, é tratada como 0.")]
    public string variableName;

    public Comparison comparison = Comparison.Equal;

    public int value = 1;

    public override bool Evaluate(EnemyController enemy)
    {
        var vars = GameVariables.Instance;
        if (vars == null) return false;

        return NpcConditionUtil.Compare(vars.GetInt(variableName), comparison, value);
    }
}

/// <summary>Desactiva o inimigo quando uma missão atinge um estado (Etapa 5.1 — ex: máquinas que desligam quando a missão é concluída).</summary>
[System.Serializable]
public class Condition_MissionStateReached : EnemyCondition
{
    public MissionData mission;

    public MissionStateCheck state = MissionStateCheck.Concluida;

    public override bool Evaluate(EnemyController enemy)
    {
        var mm = MissionManager.Instance;
        if (mm == null || mission == null) return false;

        switch (state)
        {
            case MissionStateCheck.Iniciada: return mm.IsMissionStarted(mission);
            case MissionStateCheck.NaoIniciada: return !mm.IsMissionStarted(mission);
            case MissionStateCheck.Concluida: return mm.IsMissionCompleted(mission);
            case MissionStateCheck.NaoConcluida: return !mm.IsMissionCompleted(mission);
            case MissionStateCheck.EmCurso: return mm.IsMissionStarted(mission) && !mm.IsMissionCompleted(mission);
            default: return false;
        }
    }
}
